form:Form.form:Scripts:
		function LoadForm()
{
	ONLOAD();	
}

function Ejecutar()
{
	if (Ctrl("POSICION_NEW") && Ctrl("POSICION_NEW").GetXValue() != "")
		if (!confirm('Si carga una posición se borrarán todas las plantillas de las evaluaciones y se crearán nuevamente a partir de la posición ingresada. Cualquier resultado registrado sobre la misma se perderá. Está seguro que desea continuar?')) return false;

	var required = false;
	if (Ctrl("EVALUADOR_NEW") && Ctrl("EVALUADOR_NEW").GetXValue() != "") required = true;
	if (Ctrl("SUPERVISOR_NEW") && Ctrl("SUPERVISOR_NEW").GetXValue() != "") required = true;
	if (Ctrl("POSICION_NEW") && Ctrl("POSICION_NEW").GetXValue() != "") required = true;
	if (Ctrl("update_evaluadores") && Ctrl("update_evaluadores").GetXValue() == "1") required = true;
	if (Ctrl("EVALUADOR_NEW") || Ctrl("SUPERVISOR_NEW") || Ctrl("POSICION_NEW") || Ctrl("update_evaluadores"))
	{
		if (!required)
		{
			alert("Debe ingresar por lo menos un dato a modificar (Evaluador, Supervisor, Posición u Otros Evaluadores)");
			return false;
		}
	}

	var np = new NomadProxy("", ut); 
	var nSQL = np.SQLService();   
	var cantLeg = nSQL.GetOBJ( Ctrl("main").getResource("qry_cantLegajos"));

	cantLeg.valor = Trim(cantLeg.valor.toString())

	if(cantLeg.valor.toString().length === 0 || isNaN(cantLeg.valor))
	{
		cantLeg.valor = 100;	
	}

	if (arrFILTER.length==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

 	if (arrFILTER.length>cantLeg.valor)
 	{             
 		alert("Hay demasiados registros seleccionados, afine la búsqueda.");
 		return false;
 	}

	FillArray(cantLeg.valor);

	Ctrl("main").DoEvent("FILTER");
}
